1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Step = QuoteStep;
10	
11	export type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Step[];
14	};
15	
16	export type QuoteResult = { premium: number };
17	export type ScenarioResult = { results: QuoteResult[] };
18	
19	const PROCESSING_FEE = 5;
20	const FIRST_INSURANCE_SURCHARGE = 0.1;
21	
22	const BASE_PREMIUMS: Record<string, number> = {
23	  sword: 100,
24	};
25	
26	const quoteStep = (step: QuoteStep): QuoteResult => {
27	  const itemTotal = step.items.reduce((sum, item) => {
28	    const base = BASE_PREMIUMS[item.type] ?? 0;
29	    return sum + base + base * FIRST_INSURANCE_SURCHARGE;
30	  }, 0);
31	  return { premium: itemTotal + PROCESSING_FEE };
32	};
33	
34	export const runScenario = (scenario: Scenario): ScenarioResult => {
35	  return { results: scenario.steps.map(quoteStep) };
36	};
